{"path": "src/db.rs", "content": "use crate::api::SearchResult;
use std::collections::HashMap;
use std::sync::RwLock;
use crate::distance::l2_distance;

pub struct VectorDB {
    vectors: RwLock<HashMap<u64, Vec<f32>>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            vectors: RwLock::new(HashMap::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut map = self.vectors.write().unwrap();
        map.insert(id, vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut map = self.vectors.write().unwrap();
        let count = vectors.len();
        for (id, vector) in vectors {
            map.insert(id, vector);
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let map = self.vectors.read().unwrap();

        let mut results: Vec<(u64, f64)> = map
            .iter()
            .map(|(&id, v)| (id, l2_distance(vector, v)))
            .collect();

        // Sort by distance ascending
        results.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());

        // Take top_k
        results.truncate(top_k as usize);

        results
            .into_iter()
            .map(|(id, distance)| SearchResult { id, distance })
            .collect()
    }
}
"}

{"path": "src/db.rs", "content": "use crate::api::SearchResult;
use std::sync::RwLock;
use rayon::prelude::*;

const DIM: usize = 128;

pub struct VectorDB {
    // Flat storage: all vectors stored contiguously
    // ids[i] corresponds to the vector starting at data[i*DIM..(i+1)*DIM]
    ids: RwLock<Vec<u64>>,
    data: RwLock<Vec<f32>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            ids: RwLock::new(Vec::new()),
            data: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut ids = self.ids.write().unwrap();
        let mut data = self.data.write().unwrap();
        ids.push(id);
        data.extend_from_slice(&vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut ids = self.ids.write().unwrap();
        let mut data = self.data.write().unwrap();
        let count = vectors.len();
        for (id, vector) in vectors {
            ids.push(id);
            data.extend_from_slice(&vector);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let ids = self.ids.read().unwrap();
        let data = self.data.read().unwrap();
        let n = ids.len();

        if n == 0 {
            return Vec::new();
        }

        // Parallel search: compute distances for all vectors
        let mut results: Vec<(u64, f32)> = (0..n)
            .into_par_iter()
            .map(|i| {
                let start = i * DIM;
                let vec = &data[start..start + DIM];
                let dist = l2_distance_squared(query, vec);
                (ids[i], dist)
            })
            .collect();

        // Partial sort to get top_k
        results.select_nth_unstable_by(top_k as usize - 1, |a, b| {
            a.1.partial_cmp(&b.1).unwrap()
        });
        results.truncate(top_k as usize);

        // Sort the top_k results
        results.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());

        results
            .into_iter()
            .map(|(id, dist)| SearchResult { id, distance: dist as f64 })
            .collect()
    }
}

#[inline]
fn l2_distance_squared(a: &[f32], b: &[f32]) -> f32 {
    let mut sum = 0.0f32;
    for i in 0..DIM {
        let diff = a[i] - b[i];
        sum += diff * diff;
    }
    sum
}
"}

