        let inner = self.inner.read().unwrap();
        let n = inner.ids.len();

        if n == 0 {
            return Vec::new();
        }

        let ids = &inner.ids;
        let data = &inner.data;

        // Use rayon's parallel iterator with chunking
        let chunk_size = 8192;
